import{_ as p,C as e,o as h,c as s,j as a,a as t,E as i,a3 as d}from"./chunks/framework.CVjg771q.js";const q=JSON.parse('{"title":"太上感应篇","description":"一篇从善恶感应落到日用警策的劝善短文。","frontmatter":{"title":"太上感应篇","description":"一篇从善恶感应落到日用警策的劝善短文。","category":"guide","aliases":["太上感应篇","感应篇","taishang ganying pian"],"source":["《太上感应篇》"]},"headers":[],"relativePath":"daoism/starter-texts/taishang-ganying-pian.md","filePath":"daoism/starter-texts/taishang-ganying-pian.md","lastUpdated":1779783531000}'),g={name:"daoism/starter-texts/taishang-ganying-pian.md"};function u(y,n,c,b,x,_){const r=e("DaoReadingPrelude"),o=e("DaoOriginalReading"),l=e("DaoLineGuide"),m=e("DaoKeywordCards");return h(),s("div",null,[n[0]||(n[0]=a("h1",{id:"太上感应篇",tabindex:"-1"},[t("太上感应篇 "),a("a",{class:"header-anchor",href:"#太上感应篇","aria-label":'Permalink to "太上感应篇"'},"​")],-1)),i(r,{title:"先抓住感应总纲，再看善恶条目",summary:"这篇不从玄理起，而是直接立出“祸福无门，惟人自召”的总纲。更适合的进入方式，是先顺着原文感受整篇的警策语气，再按总纲、善行、恶行、改悔四层慢慢分开读。",points:[{label:"先读",text:"先把开篇总纲与结尾改悔完整读一遍。"},{label:"再辨",text:"看善恶条目怎样从日用细处展开。"},{label:"后想",text:"最后回到“转祸为福”的余地，不把全篇只读成惩戒。"}],hint:"这篇篇幅较长，第一次读不必逐条硬记，可先抓住总纲、善行举要、恶行举列、改过迁善四个层次。"}),n[1]||(n[1]=a("h2",{id:"【原典层】原文",tabindex:"-1"},[t("【原典层】原文 "),a("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),i(o,{paragraphs:["太上曰：祸福无门，惟人自召；","善恶之报，如影随形。","是以天地有司过之神，","依人所犯轻重，以夺人算。","算减则贫耗，多逢忧患；","人皆恶之，刑祸随之；","吉庆避之，恶星灾之；","算尽则死。","又有三台北斗神君，在人头上，","录人罪恶，夺其纪算。","又有三尸神，在人身中，","每到庚申日，辄上诣天曹，言人罪过。","月晦之日，灶神亦然。","凡人有过，大则夺纪，小则夺算。","其过大小，有数百事，","欲求长生者，先须避之。","是道则进，非道则退。","不履邪径，不欺暗室；","积德累功，慈心于物；","忠孝友悌，正己化人；","矜孤恤寡，敬老怀幼；","昆虫草木，犹不可伤。","宜悯人之凶，乐人之善，","济人之急，救人之危；","见人之得，如己之得；","见人之失，如己之失；","不彰人短，不炫己长；","遏恶扬善，推多取少；","受辱不怨，受宠若惊；","施恩不求报，与人不追悔；","所谓善人，人皆敬之，","天道佑之，福禄随之，","众邪远之，神灵卫之；","所作必成，神仙可冀。","欲求天仙者，当立一千三百善；","欲求地仙者，当立三百善。","苟或非义而动，背理而行；","以恶为能，忍作残害；","阴贼良善，暗侮君亲；","慢其先生，叛其所事；","诳诸无识，谤诸同学；","虚诬诈伪，攻讦宗亲；","刚强不仁，狠戾自用；","是非不当，向背乖宜；","虐下取功，谄上希旨；","受恩不感，念怨不休；","轻蔑天民，扰乱国政；","赏及非义，刑及无辜；","杀人取财，倾人取位；","诛降戮服，贬正排贤；","凌孤逼寡，弃法受赂；","以直为曲，以曲为直；","入轻为重，见杀加怒；","知过不改，知善不为；","自罪引他，壅塞方术；","诅咒求直，嗜酒悖乱；","骨肉忿争，男不忠良，女不柔顺；","不和其室，不敬其夫；","每好矜夸，常行妒忌；","无行于妻子，失礼于舅姑；","轻慢先灵，违逆上命；","作为无益，怀挟外心；","自咒咒他，偏憎偏爱；","越井越灶，跳食跳人；","损子堕胎，行多隐僻；","晦腊歌舞，朔旦号怒；","对北涕唾及溺，对灶吟咏及哭；","又以灶火烧香，秽柴作食；","夜起裸露，八节行刑；","唾流星，指虹霓，辄指三光；","久视日月，春月燎猎；","对北恶骂，无故杀龟打蛇；","如是等罪，司命随其轻重，夺其纪算。","算尽则死，死有余责，乃殃及子孙。","又诸横取人财者，","乃计其妻子家口以当之，渐至死丧。","若不死丧，则有水火盗贼、","遗亡器物、疾病口舌诸事，","以当妄取之值。","又枉杀人者，是易刀兵而相杀也。","取非义之财者，譬如漏脯救饥，","鸩酒止渴，非不暂饱，死亦及之。","夫心起于善，善虽未为，而吉神已随之；","或心起于恶，恶虽未为，而凶神已随之。","其有曾行恶事，后自改悔，","诸恶莫作，众善奉行，","久久必获吉庆；所谓转祸为福也。","故吉人语善、视善、行善，","一日有三善，三年天必降之福；","凶人语恶、视恶、行恶，","一日有三恶，三年天必降之祸。","胡不勉而行之？"]}),i(l,{lines:[{text:"太上曰：祸福无门，惟人自召；善恶之报，如影随形。",tone:"总纲 · 先立根本",guide:"开篇先不要急着进入神祇系统，先抓住全篇真正的中心：祸福与善恶都与人的起心动念和所作所为相连。"},{text:"是以天地有司过之神……欲求长生者，先须避之。",tone:"秩序 · 强化警惕",guide:"这一段可先读成“天地间有一套追索人过的秩序”，重点不只在神名，而在于强调人的行为并不会做过就算。"},{text:"是道则进……欲求地仙者，当立三百善。",tone:"善行 · 落到日用",guide:"善并不是空泛口号，而是落实在不欺暗室、敬老怀幼、见人得失如己得失这些很具体的日常分寸里。"},{text:"苟或非义而动……乃殃及子孙。",tone:"恶行 · 镜照自身",guide:"这一长段不必一次记全，更适合当作一面镜子，看许多败坏与祸乱如何由细小偏差不断积成。"},{text:"夫心起于善……胡不勉而行之？",tone:"转向 · 留有余地",guide:"全篇最后不是把人锁死，而是留下改悔与转祸为福的路，这也是读这篇时很重要的收束处。"}]}),n[2]||(n[2]=a("h2",{id:"【原典层】字词释义",tabindex:"-1"},[t("【原典层】字词释义 "),a("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),i(m,{title:"字词释义",items:[{term:"惟人自召",pinyin:["wéi","rén","zì","zhào"],meaning:"祸福不是凭空而来，而是人自己召来的。「祸福无门，惟人自召」是全篇总纲，将一切后果拉回人的起心动念与行为上。",context:"字面意思是「只有人自己召来」，强调祸福并非外界无端施加。"},{term:"司过之神",pinyin:["sī","guò","zhī","shén"],meaning:"掌管记录人过失的神明。「天地有司过之神」象征一套追索人过的秩序——人的行为不会做过了就凭空消失。"},{term:"夺",pinyin:["duó"],meaning:"削减、剥夺。「以夺人算」指因过失而折损人的寿数与福分，不是外加惩罚，而是自己损了自己的根基。"},{term:"纪算",pinyin:["jì","suàn"],meaning:"寿数与福分的度量单位。一说纪为十二年、算为百日（或计为一算），「夺纪」「夺算」指折寿减福。"},{term:"三尸神",pinyin:["sān","shī","shén"],meaning:"居于人体内的三种神，分别在人头、腹、足中，记录人的过失，每到庚申日便上天报告。"},{term:"庚申日",pinyin:["gēng","shēn","rì"],meaning:"干支纪日中的庚申日，每六十天一遇。道教传统中此日三尸神上天言人罪过，故有守庚申的修行之法。"},{term:"辄",pinyin:["zhé"],meaning:"总是、即、就。「每到庚申日，辄上诣天曹」——时间一到，立即上天报告，强调从无遗漏。"},{term:"诣",pinyin:["yì"],meaning:"前往、到达。「辄上诣天曹」——前往天上的官署，指三尸神上天汇报。"},{term:"天曹",pinyin:["tiān","cáo"],meaning:"天上的官署，天庭审理人间善恶的办公之处，象征天地间有更高层级的记录与裁断。"},{term:"月晦之日",pinyin:["yuè","huì","zhī","rì"],meaning:"每月最后一天（月亮完全隐没之日）。「月晦之日，灶神亦然」——灶神也在这天上天报告一家善恶。"},{term:"灶神",pinyin:["zào","shén"],meaning:"主管一家善恶的神。「月晦之日，灶神亦然」——与三尸神类似，灶神也会定期上天报告，使人在家中也有敬畏。"},{term:"履",pinyin:["lǚ"],meaning:"踏、行走，引申为践行。「不履邪径」——不踏上邪僻的路径，从脚下第一步就守住正路。"},{term:"欺",pinyin:["qī"],meaning:"欺骗。「不欺暗室」——即使在无人看见的暗室之中也不欺骗本心。暗室是无人之境，最能检验一个人是否表里如一。"},{term:"暗室",pinyin:["àn","shì"],meaning:"无人看见的隐蔽之处。「不欺暗室」——真正的善，不在人前表演，而在无人处也不欺心。"},{term:"矜",pinyin:["jīn"],meaning:"怜悯、同情。「矜孤恤寡」——怜悯孤儿，体恤寡妇。矜是不轻视、不放任，恤是切实关怀。"},{term:"恤",pinyin:["xù"],meaning:"体恤、抚恤。「矜孤恤寡」——不只停留在同情，而是实际上给予关怀与照顾。"},{term:"悯",pinyin:["mǐn"],meaning:"怜悯、同情。「宜悯人之凶」——对遭遇不幸的人应当抱有怜悯，而非幸灾乐祸或冷漠旁观。"},{term:"彰",pinyin:["zhāng"],meaning:"张扬、显露。「不彰人短」——不张扬别人的短处，不给他人难堪，守住言语的分寸。"},{term:"炫",pinyin:["xuàn"],meaning:"夸耀、炫耀。「不炫己长」——不炫耀自己的长处。有长处而不显摆，是自守之德。"},{term:"遏",pinyin:["è"],meaning:"遏制、阻止。「遏恶扬善」——主动阻止恶行，弘扬善行，不只独善其身。"},{term:"冀",pinyin:["jì"],meaning:"期望、希求。「神仙可冀」——神仙境界是可以期望达到的，给人向上一路的希望。"},{term:"苟或非义",pinyin:["gǒu","huò","fēi","yì"],meaning:"假如做了不合道义的事。「苟或非义而动，背理而行」——以下长篇恶行列举的开端，以假设语气引出。"},{term:"侮",pinyin:["wǔ"],meaning:"轻慢、侮辱。「暗侮君亲」——暗地里怠慢君主与父母，在人前恭敬、背地里轻侮。"},{term:"诳",pinyin:["kuáng"],meaning:"欺骗、哄骗。「诳诸无识」——欺骗那些没有见识、不明真相的人，利用他人的无知来获利。"},{term:"谤",pinyin:["bàng"],meaning:"诽谤、说人坏话。「谤诸同学」——诽谤同门学友，背地里败坏同学名誉。"},{term:"讦",pinyin:["jié"],meaning:"揭发隐私、攻击短处。「攻讦宗亲」——攻击宗族亲人，揭其隐私短处，不顾亲情。"},{term:"诛降戮服",pinyin:["zhū","xiáng","lù","fú"],meaning:"诛杀已经投降的人，杀戮已经臣服的人。这是极不仁之事——对手已放下武器，再下杀手便是违逆天道。"},{term:"壅塞方术",pinyin:["yōng","sè","fāng","shù"],meaning:"阻碍、堵塞他人的方术技艺。「方术」指医卜星相等技能，壅塞即故意不让善法流传。"},{term:"忿",pinyin:["fèn"],meaning:"愤怒、怨恨。「骨肉忿争」——骨肉至亲之间因为愤怒和怨恨而争斗，伤了最不该伤的情分。"},{term:"朔旦号怒",pinyin:["shuò","dàn","háo","nù"],meaning:"每月初一大声号叫、发怒。朔为初一，旦为早晨。古人以朔旦为吉日，此日动怒尤不可取。"},{term:"涕唾及溺",pinyin:["tì","tuò","jí","niào"],meaning:"「对北涕唾及溺」——对着北方擤鼻涕、吐唾沫、小便。北方在传统中为尊位，此行为极不敬。"},{term:"吟咏及哭",pinyin:["yín","yǒng","jí","kū"],meaning:"「对灶吟咏及哭」——对着灶台吟诗唱歌及哭泣。灶为一家之神所居，不应在其前轻慢喧哗。"},{term:"秽柴",pinyin:["huì","chái"],meaning:"不洁净的柴火。「秽柴作食」——用污秽的柴火做饭，是对饮食与灶神的不敬。"},{term:"唾流星",pinyin:["tuò","liú","xīng"],meaning:"对着流星吐唾沫。古人以流星为天象之一，唾之即为不敬。"},{term:"指虹霓",pinyin:["zhǐ","hóng","ní"],meaning:"用手指指着彩虹。虹霓为天地之气所成，以手指之为不敬。"},{term:"辄指三光",pinyin:["zhé","zhǐ","sān","guāng"],meaning:"随意用手指指日月星三光。三光为天地间最光明之物，不应以手指随意指点。辄为总是、随意。"},{term:"春月燎猎",pinyin:["chūn","yuè","liáo","liè"],meaning:"春天焚烧山林以打猎。春为万物生发之季，燎林猎兽违背天时、残害生灵，罪加一等。"},{term:"妄取之值",pinyin:["wàng","qǔ","zhī","zhí"],meaning:"不应当取得而强取的财物及其应偿之值。「以当妄取之值」——横取而来的财物，终将以水火盗贼等方式折还。"},{term:"漏脯救饥",pinyin:["lòu","fǔ","jiù","jī"],meaning:"用腐败渗水的干肉充饥。脯为干肉，漏为腐败渗水。比喻只顾眼前解急，却忘了后面更大的危害——取非义之财也是如此。"},{term:"勉",pinyin:["miǎn"],meaning:"勉力、努力。「胡不勉而行之」——为什么不努力去实行呢？全篇最后一句，劝人从勉力实践开始。"}]}),n[3]||(n[3]=d('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><blockquote><p>解读仅个人观点，仅供参考，若有疏漏还望海涵，并批评指出</p></blockquote><h3 id="象-这篇在说什么" tabindex="-1">象：这篇在说什么 <a class="header-anchor" href="#象-这篇在说什么" aria-label="Permalink to &quot;象：这篇在说什么&quot;">​</a></h3><p>《太上感应篇》开篇就把话说得很直：“祸福无门，惟人自召；善恶之报，如影随形。”后面整篇几乎都围绕这一点展开：人的念头、言语、行为，并不会凭空消散，而会积累、转化，最终回到自己身上。</p><p>它和《清静经》《阴符经》的气质不同，不重在讲大道本体，也不重在讲天机转变，而是更直接地落到日常做人做事上。</p><h3 id="理-为什么这篇重要" tabindex="-1">理：为什么这篇重要 <a class="header-anchor" href="#理-为什么这篇重要" aria-label="Permalink to &quot;理：为什么这篇重要&quot;">​</a></h3><p>这篇重要，不在于它把人吓住，而在于它把“善恶”从空话拉回日用。</p><ul><li>它提醒人，许多后果并不是偶然掉下来的</li><li>它把抽象的“善”与“恶”列成具体行为，让人照见自身</li><li>它没有停在定罪，最后仍留下“改悔”“转祸为福”的路</li><li>它很适合作为一种日常警策，而不是只当作神秘劝善文来读</li></ul><h3 id="用-今天怎么进入这篇" tabindex="-1">用：今天怎么进入这篇 <a class="header-anchor" href="#用-今天怎么进入这篇" aria-label="Permalink to &quot;用：今天怎么进入这篇&quot;">​</a></h3><p>今天读《太上感应篇》，可以先不急着把“司过之神”“夺算”全都读成字面宗教设定，而先抓住它要提醒人的根本问题：</p><ul><li>我平常是不是总把后果归给外界，却很少回看自己？</li><li>我以为自己只是起了个念头、说了一句话，真的没有影响吗？</li><li>若我已经做错了，有没有认真改悔、转向的能力？</li></ul><p>先抓住这些问题，再回头读原文，感受会更深。</p><h2 id="【解读层】分段解读" tabindex="-1">【解读层】分段解读 <a class="header-anchor" href="#【解读层】分段解读" aria-label="Permalink to &quot;【解读层】分段解读&quot;">​</a></h2><h3 id="_1-总纲-祸福并非无端而来" tabindex="-1">1. 总纲：祸福并非无端而来 <a class="header-anchor" href="#_1-总纲-祸福并非无端而来" aria-label="Permalink to &quot;1. 总纲：祸福并非无端而来&quot;">​</a></h3><p>“祸福无门，惟人自召；善恶之报，如影随形”是全篇总纲。它先把最核心的一点立住：祸福不是凭空闯入生活的陌生东西，而往往与人的起心动念和所作所为有关。</p><p>这里的“惟人自召”也不只是一句简单的归责。它更像是在提醒人：祸福不是只在起点上决定的，而会在人的持续应对中不断长出来。事情发生之后，人怎么想、怎么对待自己、怎么继续往前走，也都在把后面的祸福慢慢召成新的样子。</p><p>而“如影随形”也不必先读成吓人的“逃不过”。影子不是外加给人的，它本来就会随着形而生。影不是本体，也不能说明全部，但它会忠实地照出一个轮廓。人的善恶、选择与行事方式也是如此：每个人的心不同，读出来的提醒也不同，可一个人活出来的痕迹，总会慢慢显现。你可以不看它、不想它，但它仍然在那里。</p><h3 id="_2-司过夺算-以秩序感强化警惕" tabindex="-1">2. 司过夺算：以秩序感强化警惕 <a class="header-anchor" href="#_2-司过夺算-以秩序感强化警惕" aria-label="Permalink to &quot;2. 司过夺算：以秩序感强化警惕&quot;">​</a></h3><p>后面大量关于司过之神、三尸神、灶神、夺纪夺算的说法，可以先理解为一种强烈的秩序感表达。它是在告诉人：人的所作所为，并不是做过就算了，而像始终有一套更大的秩序在衡量、记录、追索。</p><h3 id="_3-善行举要-把-善-落到日用里" tabindex="-1">3. 善行举要：把“善”落到日用里 <a class="header-anchor" href="#_3-善行举要-把-善-落到日用里" aria-label="Permalink to &quot;3. 善行举要：把“善”落到日用里&quot;">​</a></h3><p>这一段最重要的地方，在于它并没有把“善”说成空泛的大词，而是落在很具体的人伦和日常里：不欺暗室、慈心于物、见人之得如己之得、不彰人短、不炫己长、施恩不求报。</p><p>它不是让人空谈高远，而是回到平时最容易忽略的地方。</p><h3 id="_4-恶行举列-恶多从细处积成" tabindex="-1">4. 恶行举列：恶多从细处积成 <a class="header-anchor" href="#_4-恶行举列-恶多从细处积成" aria-label="Permalink to &quot;4. 恶行举列：恶多从细处积成&quot;">​</a></h3><p>恶行一段读来很长，也很重。若只把它当作道德清单，容易疲。更好的读法，也许是把它看成一面镜子：很多祸乱与败坏，并不是突然发生，而是从一连串细小的偏差、妄动、贪取、欺瞒、刚愎中慢慢积成。</p><h3 id="_5-改过迁善-不是定罪-而是转向" tabindex="-1">5. 改过迁善：不是定罪，而是转向 <a class="header-anchor" href="#_5-改过迁善-不是定罪-而是转向" aria-label="Permalink to &quot;5. 改过迁善：不是定罪，而是转向&quot;">​</a></h3><p>全篇最后最可贵的一点，是它没有把人锁死在“你做过恶，所以完了”。它仍然说：若能改悔，诸恶莫作，众善奉行，久而久之，仍可“转祸为福”。</p><p>这使它不只是惩戒文，也还是一篇给人留路的文字。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>一个人的祸福并不总是外界强加的，很多时候，它与自己的念头、说话方式和做事方式有关。善恶不会立刻都显出结果，但会像影子一样慢慢跟上来。</p><p>《太上感应篇》不是要人陷入恐惧，而是提醒人：后果往往早在平时就埋下了。若能从细处自省、从日用中改正、从错误里回头，那么命运并非毫无转机。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>这篇给我的第一感觉，是“直”。《清静经》会先把人带到更大的大道秩序里，《阴符经》会让人看见变化与机，而《太上感应篇》像是直接站在你面前说：你不要总怪天怪地，很多祸福本来就和你自己有关。</p><p>我读这篇的入口，其实和自己经历过的一场祸有关。一次骑车意外让我骨折，正好撞在羽毛球比赛前一周。那之后吃饭、敲代码、日常动作都变得很麻烦，整个人也短暂陷进了压抑里。回头看，这件事的源头与我自己有关，所以我也不太愿意把它全推给外界。可也正因为这场祸，我被迫慢下来，开始练另一只手，开始重新适应新的节奏，也是在那段时间里，我真正走近《易经》，走近这些文字。</p><p>所以现在再读“祸福无门，惟人自召”，我会更愿意把它理解成：祸福并不总是贴在事情表面的固定标签。祸来了，未必只停在祸；人怎么应对，怎么转身，后面的路也会慢慢变。那场意外是祸，但它也逼我慢下来，看见周边的世界，宽恕过去的自己，重新开始学习和整理。这样回看时，我反而觉得，福有时正是从祸里慢慢长出来的。</p><p>我觉得它的可贵之处，不只是讲“善恶有报”，而是把这件事讲得很细。不是只说“你要做个好人”，而是把许多平时最容易被忽略的地方一条条摆出来。这样读的时候，人反而很难只停在抽象认同上，因为总会有几句照到自己。</p><p>但我现在也不太愿意把它读成一篇单纯吓人的文章。若只剩恐惧，那人可能只是表面收敛，心里并没有真的转。相比之下，我更在意它最后留的那条路：若曾行恶，后自改悔，诸恶莫作，众善奉行，久久必获吉庆。也就是说，它不是只在追责，也还是在劝人回头。</p><p>而“善恶之报，如影随形”对我来说，也不只是吓人的“报应”说法。人的念头、选择、应对方式，都会像影子一样慢慢跟上来。那段时间里，我开始放下比较，接受自己的平凡，接受一些所谓失败，继续按自己的节奏去做自己觉得正确的事。现在回头看，那些当时看似很小的转念和行动，也都一路跟着我，走到了今天。</p><p>现在再读“惟人自召”，我更愿意把它理解成一种持续生成。人当然要为自己的选择负责，但更重要的是，事情发生之后，自己怎么应对、怎么转向，也都在不断把后面的祸福召出来。这样一来，祸福就不只是外在降临的结果，而像是在人的一念一行里继续长成。</p><p>而“如影随形”对我来说，也越来越像一个更深的比喻。影不是本体，也不能代表全部，但它会很忠实地照出一个轮廓。人的生命状态也是如此：很多事情并不是简单二元的，可即便如此，一个人活出来的走向，仍会慢慢投出自己的影子。这个影未必是为了定罪，反而更像一种善意的提醒，让人看见自己大致正在往哪里去。</p><p>所以这篇我会更愿意把它当作一面镜子。不是天天拿来审判别人，而是偶尔照一照自己：哪些地方已经偏了，哪些地方仍能转回来。若真能从照见自己开始，再一点点改，这篇文字就不是只会让人害怕，而是会真正帮人活得更清醒一些。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《太上感应篇》</li><li><a href="https://zh.wikisource.org/wiki/%E5%A4%AA%E4%B8%8A%E6%84%9F%E6%87%89%E7%AF%87" target="_blank" rel="noreferrer">维基文库：太上感應篇</a></li></ul>',42))])}const k=p(g,[["render",u]]);export{q as __pageData,k as default};
